    for (int d = 0; d < NUM_DIRECTIONS; ++d) {
        if (dir_counts[d] > 0) {
            double avg = dir_scores[d] / dir_counts[d];
            if (avg > best_score) {
                best_score = avg;
                best_dir = d;
            }
        }
    }

